import"./auth-DfyYPuF3.js";const a=document.querySelector(".container"),i=document.querySelector(".register-btn"),l=document.querySelector(".login-btn");i.addEventListener("click",()=>a.classList.add("active"));l.addEventListener("click",()=>a.classList.remove("active"));function c(s,n="success"){const o=document.getElementById("toastContainer"),e=document.createElement("div");e.className=`toast ${n}`;const t=n==="success"?"bx-check-circle":"bx-error-circle";e.innerHTML=`<i class='bx ${t}'></i> <span>${s}</span>`,o.appendChild(e),setTimeout(()=>e.classList.add("active"),10),setTimeout(()=>{e.classList.remove("active"),setTimeout(()=>e.remove(),400)},3e3)}const d=document.getElementById("regForm");d.onsubmit=async function(s){s.preventDefault();const n=document.getElementById("regFullName").value,o=document.getElementById("regEmail").value,e=document.getElementById("regPassword").value,t=document.getElementById("regBtn");try{t.disabled=!0,t.innerHTML='<span class="loader"></span> Жүктелуде...',await auth.register(o,e,n),c("Тіркелу сәтті! Енді жүйеге кіре аласыз.","success"),setTimeout(()=>{a.classList.remove("active"),t.disabled=!1,t.innerHTML="Тіркелу"},2e3)}catch(r){c(r.message,"error"),t.disabled=!1,t.innerHTML="Тіркелу"}};const m=document.getElementById("loginForm");m.onsubmit=async function(s){s.preventDefault();const n=document.getElementById("loginEmail").value,o=document.getElementById("loginPassword").value,e=document.getElementById("loginBtn");try{e.disabled=!0,e.innerHTML='<span class="loader"></span> Кіру...',await auth.login(n,o),c("Қош келдіңіз!","success"),window.location.href="register1.html#home"}catch(t){c(t.message,"error"),e.disabled=!1,e.innerHTML="Кіру"}};
